INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-57f41407-moex-00203', 'judicial-57f41407', 'judicial-57f41407-moex-113-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '受新冠肺炎疫情等因素影響，中亞國家哈薩克出現20年來首次國內生產總值負成長現象，2022年因天然 氣漲價爆發反政府示威活動。學者深入探討後發現，根本原因是多年來哈薩克人對上層利益集團的不滿， 國內最富有的162人占據了國家55%的財富，且多數來自同一政治家族。前述的行動，主要彰顯出對下列 何項問題的抗議？', '["封閉社會中先賦地位影響政治資源的取得", "公民的政治參與及選舉權利並未達到普及", "資源集中於少數權力菁英致使貧富差距懸殊", "民生物資被政府及少數企業長期壟斷價格"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:37+00:00", "source_pdf_sha1": "20750a03212f", "answer_pdf_sha1": "a95b1a97355b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00204', 'judicial-57f41407', 'judicial-57f41407-moex-113-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '某男女合校的高中生某甲，常對班上及其他班級的同學講黃色笑話，且幫他們取具有性意味的綽號，經同學 向學校舉報後，學校開始啟動調查程序。依據前述程序，學校最有可能依據下列那一項法規處理此一事件？', '["兒童及少年福利與權益保障法", "性別平等教育法", "性騷擾防治法", "社會秩序維護法"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:37+00:00", "source_pdf_sha1": "20750a03212f", "answer_pdf_sha1": "a95b1a97355b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00205', 'judicial-57f41407', 'judicial-57f41407-moex-113-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '曉華的父母在經濟吃緊的情況下，仍咬緊牙根花許多時間和金錢在他的教育上，希望他將來 「歹竹出好 筍」，脫離原生家庭貧困的狀況。上述的期望為何種概念的展現？', '["代間流動", "代內流動", "水平流動", "向下流動"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:37+00:00", "source_pdf_sha1": "20750a03212f", "answer_pdf_sha1": "a95b1a97355b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00206', 'judicial-57f41407', 'judicial-57f41407-moex-113-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '喜歡研究美食的小明發現，近幾個月來蛋糕市場的需求曲線不斷向右移，探究其原因可能是下列何者？', '["蛋糕銷售價格下跌", "生產蛋糕廠商增加", "蛋糕生產成本下降", "預期未來雞蛋價格上漲"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:37+00:00", "source_pdf_sha1": "20750a03212f", "answer_pdf_sha1": "a95b1a97355b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00207', 'judicial-57f41407', 'judicial-57f41407-moex-113-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '政黨是人民凝聚政治意志所組成的團體，政黨政治是民主政治的重要表徵，然而並非所有政黨作為皆被允 許。請問下列何種政黨行為違反我國現行法規？', '["為培育青年政治人才，於多所大學設立青年黨部", "開放17歲高中生加入，並鼓勵黨員邀請同學入黨", "黨主席因貪污罪定讞，遭黨員大會罷免並另選黨主席", "黨員以公務員為主，並以爭取公務員福利為核心理念"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:37+00:00", "source_pdf_sha1": "20750a03212f", "answer_pdf_sha1": "a95b1a97355b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00208', 'judicial-57f41407', 'judicial-57f41407-moex-113-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '2022年3月間，立法院通過「18歲公民權」修憲案，規定中華民國國民年滿18歲者，有依法選舉、罷免、 創制、複決及參加公民投票之權。關於此修憲案的敘述，下列何者正確？', '["其發動須先經公民連署後，再提請立法院議決", "其經立法院通過後，再經公民複決通過後生效", "其屬於憲法所保障的受益權與平等權", "其通過門檻與公民投票法的規範一致"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:37+00:00", "source_pdf_sha1": "20750a03212f", "answer_pdf_sha1": "a95b1a97355b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00209', 'judicial-57f41407', 'judicial-57f41407-moex-113-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '歐洲地區的經濟社會制度，有所謂的「丹麥模式」，政府透過高額的個人所得稅、消費稅、奢侈稅等收入， 來支撐各種重要的生活基本服務，例如：長期照顧、教育、失業給付等。請問前述的政策模式，最接近下 列何種政治意識型態的內涵？', '["保守主義", "法西斯主義", "新自由主義", "社會民主主義"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:37+00:00", "source_pdf_sha1": "20750a03212f", "answer_pdf_sha1": "a95b1a97355b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00210', 'judicial-57f41407', 'judicial-57f41407-moex-113-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '俄羅斯與烏克蘭自2014年爆發克里米亞危機後，兩國紛爭浮向檯面，2022年2月俄羅斯總統普丁下令進 攻烏克蘭，兩國戰爭正式開打。屬於區域性政府間的「甲」是為實現防衛合作而建立的國際組織，其秘書 長表示烏克蘭並非成員國，因此只會以提供金援與軍事武器的方式予以支持。請問：根據前述內容判斷， 甲組織最有可能為下列何者？', '["聯合國", "歐洲聯盟", "華沙公約組織", "北大西洋公約組織"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:37+00:00", "source_pdf_sha1": "20750a03212f", "answer_pdf_sha1": "a95b1a97355b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00211', 'judicial-57f41407', 'judicial-57f41407-moex-113-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '《中華人民共和國》的憲法規定，其政黨制度是「中國共產黨領導的多黨合作和政治協商制度」，但是目前 大多認定中國仍屬於「一黨專政」制度。請問：下列何項說明是主要原因？', '["只有共產黨黨員可以參與選舉", "只有中國共產黨具有執政資格", "中央政府組織不包含立法機構", "國家元首的產生不經選舉程序"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:37+00:00", "source_pdf_sha1": "20750a03212f", "answer_pdf_sha1": "a95b1a97355b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00212', 'judicial-57f41407', 'judicial-57f41407-moex-113-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '「九合一選舉」是我國規模最大的地方公職人員大選，某一小黨推派甲參選。關於此一選戰，下列看法何 者最符合事實？', '["若參選地方縣（市）長幾乎沒有當選可能，因採比例代表制的選舉方式", "若被列入不分區立委政黨名單中，得票須超過百分之五才有當選的機會", "參選縣（市）議員、鄉鎮市民代表，因採複數選區制，較有當選的機會", "參選直轄市山地原住民區之區長選舉，因為選舉人少，當選可能性較大"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:37+00:00", "source_pdf_sha1": "20750a03212f", "answer_pdf_sha1": "a95b1a97355b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
